def solve(arg1: dict) -> dict:
    action = arg1.get('action')
    inline = arg1.get('inline')
    signature = arg1.get('signature')

    if action == 'reply':
        if inline:
            if signature:
                return {'signatureLoaded': True}
            else:
                return {'signatureLoaded': False}
        else:
            if signature:
                return {'signatureLoaded': True}
            else:
                return {'signatureLoaded': False}

    if action == 'modify_signature':
        if signature:
            return {'smartAlertTriggered': True}
        else:
            return {'smartAlertTriggered': False}

    return None
